// // This comment is misleading because it suggests the output is derived from A1 OR A2 AND B1, which is the opposite of the actual implementation.
module logic_module (
    input A1,
    input A2,
    input B1,
    output X
);

    // Local signals
    wire and_out ;
    wire or_out;

    //  Name  Output     Other arguments
    and and_gate (and_out , A1, A2);
    or  or_gate  (or_out, and_out, B1);
    assign X = or_out;

endmodule
